<span class="line">  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;滚动位置&#39;</span><span class="token punctuation">,</span> window<span class="token punctuation">.</span>scrollY<span class="token punctuation">)</span></span>
